import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { HTMLAttributes, ReactNode } from 'react';
export type InformerSemantic = 'brand' | 'danger' | 'neutral' | 'warning' | 'info' | 'success';
/**
 * Размеры информера.
 * medium → 16px (контент) / 6px (точка)
 * large  → 20px (контент) / 8px (точка)
 */
export type InformerSize = 'medium' | 'large';
/**
 * Публичные пропсы Informer.
 *
 * Варианты использования:
 * - content: string | number → бейдж с текстом/числом
 * - content: Icons → бейдж с иконкой
 * - content не задан → точка (dot)
 */
export interface InformerProps extends Omit<HTMLAttributes<HTMLSpanElement>, 'content'> {
    /**
     * Содержимое бейджа.
     * - string | number → текст/число
     * - Icons → иконка
     * - undefined → точка (dot)
     */
    content?: string | number | Icons;
    /**
     * Семантический цвет информера.
     */
    semantic?: InformerSemantic;
    /**
     * Размер информера.
     */
    size?: InformerSize;
    /**
     * Элемент, к которому "прикрепляется" информер (как бейдж).
     */
    children?: ReactNode;
    /**
     * Пользовательский класс.
     */
    className?: string;
    /**
     * Идентификатор для тестов. По умолчанию 'Informer'.
     */
    dataTestId?: string;
}
